def twoPointerSum(i, j, nums, sum, tripletSet):
    while i<j:
        currSum = nums[i] + nums[j]
        if currSum<sum:
            i += 1
        elif currSum>sum:
            j -= 1
        else:
            tripletSet.add((-sum, nums[i], nums[j]))
            i += 1

