class Solution:
    def findAnagrams(self, s: str, p: str):
        need = Counter(p)
        left, right, n = 0, 0, len(s)
        indices = []
        while right<n:
            if s[right] not in need:
                right += 1
                left = right
                need = Counter(p)
            else:
                if need[s[right]]==0:
                    while left<=right and s[left]!=s[right]:
                        if s[left] in need:
                            need[s[left]] += 1
                        left += 1
                    left += 1
                else:
                    need[s[right]] -= 1
                    if sum(need.values())==0:
                        indices.append(left)
                        need[s[left]] += 1
                        left += 1
                right += 1
        return indices


class Solution:
    def findAnagrams(self, s: str, p: str):
        lenOfS, lenOfP, hashOfS, hashOfP, indices, counterOfP = len(s), len(p), 0, 0, [], Counter(p)
        if lenOfP>lenOfS: return []
        for i in range(lenOfP):
            hashOfP += hash(p[i])
            hashOfS += hash(s[i])
        if hashOfS==hashOfP and Counter(s[0:lenOfP])==counterOfP: indices.append(0)
        for i in range(lenOfP, lenOfS):
            hashOfS = hashOfS + hash(s[i]) - hash(s[i-lenOfP])
            if hashOfS==hashOfP and Counter(s[i+1:i+lenOfP+1])==counterOfP: indices.append(i-lenOfP+1)
        return indices

class Solution:
    def totalFruit(self, fruits):
        fruitToLastSeenIndexMap = {}
        firstIndexInSubarray, maxFruitsInBasket = 0, 0
        for index, fruit in enumerate(fruits):
            if fruit in fruitToLastSeenIndexMap or len(fruitToLastSeenIndexMap)<2:
                fruitToLastSeenIndexMap[fruit] = index
            else:
                minIndexOfFruitThatAreInBasket = min(fruitToLastSeenIndexMap.values())
                del fruitToLastSeenIndexMap[fruits[minIndexOfFruitThatAreInBasket]]
                fruitToLastSeenIndexMap[fruit] = index
                firstIndexInSubarray = minIndexOfFruitThatAreInBasket + 1
            maxFruitsInBasket = max(maxFruitsInBasket, index - firstIndexInSubarray + 1)
        return maxFruitsInBasket

class Solution:
    def longestSubarray(self, nums: List[int]) -> int:
        left, right, n = 0, 0, len(nums)
        hasZero, bestWindowLength = False, 0
        while right<n:                
            if nums[right]==0:
                if hasZero:
                    while nums[left]==1: left += 1 # skip all ones
                    left += 1 # skip that left zero
                else:
                    hasZero = True
            right += 1
            bestWindowLength = max(bestWindowLength, right-left-1 if hasZero else right-left)
        return bestWindowLength if bestWindowLength!=n else n-1


class Solution:
    def longestSubarray(self, nums: List[int]) -> int:
        left, right, n = 0, 0, len(nums)
        numZeroes, bestWindowLength = 0, 0
        while right<n:
            numZeroes += (nums[right]==0)
            while numZeroes>1: 
                numZeroes -= (nums[left]==0)
                left += 1
            bestWindowLength = max(bestWindowLength, right-left)
            right += 1
        return bestWindowLength

def longestPalindrome(s: str) -> str:

    longestPalindromeTuple = (0,0)
    n = len(s)
    for i in range(n):

        right = i+1
        while right<n and s[right-1]==s[right]:
            right += 1

        left = i-1
        while left>=0 and right<n and s[left]==s[right]:
            left -= 1
            right += 1

        if longestPalindromeTuple[1]-longestPalindromeTuple[0]+1 < right-left-1:
            longestPalindromeTuple = (left+1, right-1)

    return s[longestPalindromeTuple[0]:longestPalindromeTuple[1]+1]

