    def checkInclusion(self, s1: str, s2: str):
        need = Counter(s1)
        left, right, n = 0, 0, len(s2)
        while right<n:
            if s2[right] not in need:
                right += 1
                left = right
                need = Counter(s1)
            else:
                if need[s2[right]]==0:
                    while left<=right and s2[left]!=s2[right]:
                        if s2[left] in need:
                            need[s2[left]] += 1
                        left += 1
                    left += 1
                else:
                    need[s2[right]] -= 1
                    if sum(need.values())==0:
                        return True
                right += 1
        return False

class Solution:
    def fullJustify(self, words: List[str], maxWidth: int) -> List[str]:

        def getJustifiedString(selectedWords):
            if len(selectedWords)==1:
                return selectedWords[0] + "".join([" "]*(maxWidth - len(selectedWords[0])))

            numSpaces, numGaps = maxWidth - sum(map(len, selectedWords)), len(selectedWords)-1
            spacedWords = []

            for word in selectedWords:
                spacesToAdd = ceil(numSpaces/numGaps) if numGaps!=0 else 0
                numSpaces -= spacesToAdd
                numGaps -= 1
                spacedWords.append(word + "".join([" "]*(spacesToAdd)))

            return "".join(spacedWords)


        justifiedStrings = []
        left, right, n = 0, 0, len(words)
        while True:
            currWidth = len(words[left])
            while right+1<n and len(words[right+1])+1+currWidth<=maxWidth:
                currWidth += (len(words[right+1])+1)
                right += 1
            if right!=n-1:
                justifiedStrings.append(getJustifiedString(words[left:right+1]))
                left = right = right + 1
            else:
                justifiedStrings.append(getJustifiedString([" ".join(words[left:right+1])]))
                break

        return justifiedStrings

class Solution:
    def fullJustify(self, words: List[str], maxWidth: int) -> List[str]:

        currWords, currLength, justifiedStrings = [], 0, []
        for word in words:
            if len(word) + len(currWords) + currLength > maxWidth: # if this word cant be added to existing group
                for i in range(maxWidth - currLength):
                    currWords[i%(len(currWords)-1 or 1)] += " "
                justifiedStrings.append(''.join(currWords))
                currWords, currLength = [], 0
            currWords.append(word)
            currLength += len(word)

        return justifiedStrings + [' '.join(currWords).ljust(maxWidth)]

class Solution:
    def threeEqualParts(self, arr):
        n = len(arr)
        leftPointer, leftValue = 0, arr[0]
        rightPointer, rightValue = n-1, arr[n-1]
        midValue = int(''.join(str(arr[i]) for i in range(1, n-1)), 2)
        while midValue>=rightValue and leftPointer<rightPointer:
            if leftValue==midValue==rightValue:
                return [leftPointer, rightPointer]
            if leftValue > rightValue:
                rightValue += pow(2, n-rightPointer)*arr[rightPointer-1]
                midValue //= 2
                rightPointer -= 1
            else:
                leftValue = 2*leftValue + arr[leftPointer+1]
                midValue %= pow(2, rightPointer - leftPointer - 2)
                leftPointer += 1
        return [-1,-1] 

    def threeEqualParts(self, arr):
        numOnes, n = sum(arr), len(arr)
        if numOnes==0: return [0,n-1]
        if not numOnes%3==0: return [-1,-1]
        pointers = [-1,-1,-1]
        onesSeen = 0
        for index, num in enumerate(arr):
            if num==1:
                onesSeen += 1
                for i in range(3):
                    if (numOnes/3)*i+1 == onesSeen:
                        pointers[i] = index
        while pointers[2] < n and arr[pointers[0]] == arr[pointers[1]] == arr[pointers[2]]:
            for i in [0,1,2]:
                pointers[i] += 1
        if pointers[2] == n:
            return [pointers[0]-1, pointers[2]-1]

        return [-1, -1]

class Solution:
    def trap(self, height: list[int]) -> int:
        if not height:
            return 0

        total = 0
        n = len(height)

        for i in range(n):
            # Find max height to the left
            left_max = 0
            for j in range(i + 1):
                left_max = max(left_max, height[j])

            # Find max height to the right
            right_max = 0
            for j in range(i, n):
                right_max = max(right_max, height[j])

            # Water trapped at index i
            total += min(left_max, right_max) - height[i]

        return total

class Solution:
    def trap(self, height: list[int]) -> int:
        if not height:
            return 0

        n = len(height)
        left_max = [0] * n
        right_max = [0] * n

        # Build left_max array
        left_max[0] = height[0]
        for i in range(1, n):
            left_max[i] = max(left_max[i - 1], height[i])

        # Build right_max array
        right_max[n - 1] = height[n - 1]
        for i in range(n - 2, -1, -1):
            right_max[i] = max(right_max[i + 1], height[i])

        # Calculate trapped water
        total = 0
        for i in range(n):
            total += min(left_max[i], right_max[i]) - height[i]

        return total

class Solution:
    def trap(self, height: list[int]) -> int:
        if not height:
            return 0

        left, right = 0, len(height) - 1
        left_max, right_max = height[left], height[right]
        total = 0

        while left < right:
            if left_max < right_max:
                # Water at left is determined by left_max
                left += 1
                left_max = max(left_max, height[left])
                total += left_max - height[left]
            else:
                # Water at right is determined by right_max
                right -= 1
                right_max = max(right_max, height[right])
                total += right_max - height[right]

        return total

class Solution:
    def trap(self, height: list[int]) -> int:
        if not height:
            return 0

        stack = []  # indices where height is decreasing
        total = 0

        for i, h in enumerate(height):
            # Pop bars shorter than current and calculate trapped water
            while stack and height[stack[-1]] < h:
                top = stack.pop()
                if not stack:
                    break
                # Water trapped between stack[-1] and i, above height[top]
                distance = i - stack[-1] - 1
                bounded_height = min(height[stack[-1]], h) - height[top]
                total += distance * bounded_height
            stack.append(i)

        return total
